const express = require('express');
const bcrypt = require('bcryptjs');
const crypto = require('crypto');
const pool = require('../lib/db');
const {
  generateToken,
  generateLongToken,
  generateRefreshToken,
  rotateRefreshToken,
  revokeAllTokens,
  authMiddleware
} = require('../lib/auth');

const router = express.Router();

// ============= EMAIL/PASSWORD AUTH =============

// Register
router.post('/register', async (req, res) => {
  try {
    const { email, password, name, role = 'candidate', company_name } = req.body;

    if (!email || !password) {
      return res.status(400).json({ error: 'Email and password are required' });
    }

    // Check if user exists
    const existing = await pool.query('SELECT id FROM users WHERE email = $1', [email]);
    if (existing.rows.length > 0) {
      return res.status(400).json({ error: 'Email already registered' });
    }

    // Hash password
    const password_hash = await bcrypt.hash(password, 10);

    // Create user
    const result = await pool.query(
      `INSERT INTO users (email, password_hash, name, role, company_name)
       VALUES ($1, $2, $3, $4, $5)
       RETURNING id, email, name, role, company_name, created_at`,
      [email, password_hash, name, role, company_name]
    );

    const user = result.rows[0];
    const accessToken = generateToken(user);
    const { token: refreshToken } = await generateRefreshToken(user.id);

    res.json({
      success: true,
      user: { id: user.id, email: user.email, name: user.name, role: user.role },
      token: accessToken,
      accessToken,
      refreshToken
    });
  } catch (err) {
    console.error('Registration error:', err);

    if (err.code === '23505') {
      return res.status(400).json({ error: 'This email is already registered' });
    }
    if (err.code === '42703') {
      return res.status(500).json({ error: 'Database schema error. Please try again in a few minutes.' });
    }

    res.status(500).json({ error: 'Registration failed. Please try again.' });
  }
});

// Login
router.post('/login', async (req, res) => {
  try {
    const { email, password } = req.body;

    if (!email || !password) {
      return res.status(400).json({ error: 'Email and password are required' });
    }

    const result = await pool.query('SELECT * FROM users WHERE email = $1', [email]);
    if (result.rows.length === 0) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const user = result.rows[0];

    // Check if user has password (might be OAuth-only user)
    if (!user.password_hash) {
      return res.status(401).json({
        error: 'This account uses social login. Please sign in with Google or LinkedIn.',
        oauth_only: true
      });
    }

    const validPassword = await bcrypt.compare(password, user.password_hash);
    if (!validPassword) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const accessToken = generateToken(user);
    const { token: refreshToken } = await generateRefreshToken(user.id);
    req.session.token = accessToken;

    res.json({
      success: true,
      user: {
        id: user.id,
        email: user.email,
        name: user.name,
        role: user.role,
        is_paid: user.is_paid
      },
      token: accessToken,
      accessToken,
      refreshToken
    });
  } catch (err) {
    console.error('Login error:', err);
    res.status(500).json({ error: 'Login failed' });
  }
});

// Refresh token endpoint
router.post('/refresh', async (req, res) => {
  try {
    const { refreshToken } = req.body;

    if (!refreshToken) {
      return res.status(400).json({ error: 'Refresh token required' });
    }

    const result = await rotateRefreshToken(refreshToken);

    if (result.error) {
      return res.status(401).json({ error: result.error });
    }

    res.json({
      success: true,
      accessToken: result.accessToken,
      refreshToken: result.refreshToken,
      user: result.user
    });
  } catch (err) {
    console.error('Token refresh error:', err);
    res.status(500).json({ error: 'Token refresh failed' });
  }
});

